// 스코어별 확률 (출처: KickOff.co.uk, 2026.6.12 기준 Correct Score 예측)
// https://www.kickoff.co.uk/world-cup-predictions-stats-odds/mexico-vs-south-korea/
// ───────────────────────────────────────────────
const REAL_PROBS = {
  "1-0": 0.14, "1-1": 0.12, "2-0": 0.11, "2-1": 0.09, "0-0": 0.09,
  "0-1": 0.08, "3-0": 0.06, "1-2": 0.05, "3-1": 0.05, "2-2": 0.04,
  "0-2": 0.03, "4-0": 0.02, "3-2": 0.02, "4-1": 0.02, "1-3": 0.02,
};

function poisson(lambda, k) {
  return (Math.pow(lambda, k) * Math.exp(-lambda)) / factorial(k);
}
function factorial(n) {
  return n <= 1 ? 1 : n * factorial(n - 1);
}

const LAMBDA_MEX = 1.6;
const LAMBDA_KOR = 0.9;

function buildScores() {
  const emojiPool = ["😬","🤝","💤","📉","🔥","😤","🎉","🥶","🍿","🚀","🐯","😭","😱","🤯","🥳","😵","🙃","😎","🫠","🤡","🫨","🥴","😶‍🌫️","🤪","🦴"];
  const raw = [];
  for (let m = 0; m <= 4; m++) {
    for (let k = 0; k <= 4; k++) {
      const diff = Math.abs(m - k);
      if (diff >= 5) continue;
      const key = `${m}-${k}`;
      const prob = REAL_PROBS[key] != null
        ? REAL_PROBS[key]
        : poisson(LAMBDA_MEX, m) * poisson(LAMBDA_KOR, k) * 0.6;
      raw.push({ home: m, away: k, label: `한국 ${k} : ${m} 멕시코`, prob, source: REAL_PROBS[key] != null ? "real" : "est" });
    }
  }
  const sumRaw = raw.reduce((a, b) => a + b.prob, 0);
  const bigDiffProb = Math.max(0.01, 1 - sumRaw);
  const halfProb = bigDiffProb / 2;
  raw.push({ home: "5+", away: "KOR", label: "거인화 손흥민, 멕시코 성벽 박살 (한국 5점차 이상 대승)", prob: halfProb, source: "est" });
  raw.push({ home: "5+", away: "MEX", label: "초대형 거인 멕시코 등장, 한국 성벽 함락 (한국 5점차 이상 대패)", prob: halfProb, source: "est" });

  const sorted = [...raw].sort((a, b) => b.prob - a.prob);
  const n = sorted.length;
  sorted.forEach((s, idx) => {
    const bucket = Math.floor((idx / n) * 7) + 1;
    s.hours = Math.min(bucket, 7);
  });
  sorted.filter((s) => s.home === "5+").forEach((s) => { s.hours = 7; });

  const display = [...sorted].sort((a, b) => {
    if (a.hours !== b.hours) return a.hours - b.hours;
    return b.prob - a.prob;
  });

  return display.map((s, i) => ({
    ...s,
    emoji: emojiPool[i % emojiPool.length],
  }));
}

const SCORES = buildScores();

