const leaderboard = useMemo(() => {
    const rows = [];
    Object.entries(members).forEach(([idx, entries]) => {
      const s = SCORES[Number(idx)];
      entries.forEach((e) => {
        const sameScoreCount = entries.length;
        rows.push({
          ...e,
          scoreLabel: s.home === "5+"
            ? (s.away === "KOR" ? "한국 5점차 이상 대승" : "한국 5점차 이상 대패")
            : `${s.away}:${s.home}`,
          prob: s.prob,
          hours: s.hours,
          perPersonHours: (s.hours / sameScoreCount).toFixed(1),
        });
      });
    });
    const sorted = rows.sort((a, b) => b.hours - a.hours || a.prob - b.prob);

    // 단장(히딩크)은 항상 맨 마지막에 고정
    const masterEntry = roster.find((r) => r.title === MASTER_TITLE);
    if (masterEntry) {
      sorted.push({
        name: masterEntry.name,
        displayName: masterEntry.displayName,
        img: masterEntry.img,
        scoreLabel: "아무도 못 맞춘다 😈",
        prob: 0.999,
        hours: 0,
        perPersonHours: "0",
        isMaster: true,
      });
    }
    return sorted;
  }, [members, roster]);
  
  const squadAverages = useMemo(() => {
    const memberSquad = {};
    roster.forEach((r) => {
      memberSquad[r.name] = r.squad || (SQUAD_MEMBERS.find((m) => m.name === r.name) || {}).squad;
    });

    const sums = {};
    SQUAD_ORDER.forEach((sq) => { sums[sq] = { kor: 0, mex: 0, count: 0 }; });

    Object.entries(members).forEach(([idx, entries]) => {
      const s = SCORES[Number(idx)];
      let korGoals, mexGoals;
      if (s.home === "5+") {
        if (s.away === "KOR") { korGoals = 5; mexGoals = 0; }
        else { korGoals = 0; mexGoals = 5; }
      } else {
        mexGoals = s.home;
        korGoals = s.away;
      }
      entries.forEach((e) => {
        const sq = memberSquad[e.name];
        if (sq && sums[sq]) {
          sums[sq].kor += korGoals;
          sums[sq].mex += mexGoals;
          sums[sq].count += 1;
        }
      });
    });

    const withAvg = SQUAD_ORDER.map((sq) => ({
      squad: sq,
      label: SQUAD_LABEL[sq],
      count: sums[sq].count,
      avgKor: sums[sq].count > 0 ? (sums[sq].kor / sums[sq].count) : null,
      avgMex: sums[sq].count > 0 ? (sums[sq].mex / sums[sq].count) : null,
    }));

    // 확률 계산: 스쿼드 평균과 가까운 스코어일수록 그 스코어의 실제 확률을 더 많이 반영
    const weighted = withAvg.map((row) => {
      if (row.count === 0) return { ...row, winProb: 0, _raw: 0 };

      // 1) 각 SCORES 항목에 대해 "스쿼드 평균과의 근접도(weight)" 계산
      const weights = SCORES.map((s) => {
        let korGoals, mexGoals;
        if (s.home === "5+") {
          if (s.away === "KOR") { korGoals = 5; mexGoals = 0; }
          else { korGoals = 0; mexGoals = 5; }
        } else {
          mexGoals = s.home;
          korGoals = s.away;
        }
        const diff = Math.abs(row.avgKor - korGoals) + Math.abs(row.avgMex - mexGoals);
        // diff가 클수록 빠르게 작아지는 가중치 (제곱 커널)
        return 1 / (1 + diff * diff);
      });

      // 2) weight를 정규화해서 "스쿼드 평균 주변에 확률을 어떻게 분배할지"의 분포로 만듦
      const weightSum = weights.reduce((a, b) => a + b, 0);
      const normWeights = weightSum > 0 ? weights.map((w) => w / weightSum) : weights;

      // 3) 그 분포로 각 스코어의 실제 확률을 가중 합산
      //    → 스쿼드 평균 근처에 확률이 몰려있을수록 raw 값이 커짐
      let raw = 0;
      SCORES.forEach((s, i) => {
        raw += normWeights[i] * s.prob;
      });

      return { ...row, _raw: raw };
    });

    // 4) 4개 스쿼드의 raw 값을 합이 100%가 되도록 정규화
    const totalRaw = weighted.reduce((sum, r) => sum + r._raw, 0);
    const normalized = weighted.map((r) => ({
      ...r,
      winProb: totalRaw > 0 ? r._raw / totalRaw : 0,
    }));
/*
    const ranked = [...normalized].sort((a, b) => b.winProb - a.winProb);
*/
    const ranked = [...normalized].sort((a, b) => a.winProb - b.winProb);

    
    const rankMap = {};
    ranked.forEach((r, i) => { rankMap[r.squad] = i + 1; });

    return normalized.map((r) => ({ ...r, rank: rankMap[r.squad] }));
  }, [members, roster]);

